1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	interface QuoteStep {
9	  items: Item[];
10	}
11	
12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const FIRST_INSURANCE_SURCHARGE = 0.1;
18	const CURSE_SURCHARGE = 0.5;
19	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT = 0.2;
22	const LOYALTY_THRESHOLD_YEARS = 2;
23	const FOLLOWUP_DISCOUNT = 0.15;
24	
25	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	};
31	
32	const COMPONENT_TYPES = ["rune", "moonstone"];
33	const COMPONENT_PREMIUM = 25;
34	const BLOCK_SIZE = 3;
35	const BLOCK_PREMIUM = 60;
36	
37	// Sum `valueOf` applied to each element of an iterable.
38	const sumOf = <T>(values: Iterable<T>, valueOf: (value: T) => number): number => {
39	  let sum = 0;
40	  for (const value of values) sum += valueOf(value);
41	  return sum;
42	};
43	
44	const isComponent = (item: Item): boolean =>
45	  COMPONENT_TYPES.includes(item.type);
46	
47	const isMainItem = (item: Item): boolean => !isComponent(item);
48	
49	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
50	// BLOCK_PREMIUM; any other count is priced per component.
51	const componentGroupBasePremium = (count: number): number =>
52	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
53	
54	// An item-specific surcharge adds `rate` of the item's base premium when its
55	// condition holds, and nothing otherwise.
56	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
57	  applies ? rate * basePremiumForItem(item) : 0;
58	
59	// Cursed items add a surcharge equal to CURSE_SURCHARGE of their base premium.
60	const curseSurcharge = (item: Item): number =>
61	  surchargeWhen(item, item.cursed ?? false, CURSE_SURCHARGE);
62	
63	// Highly enchanted items (enchantment at or above the threshold) add a
64	// surcharge equal to HIGH_ENCHANTMENT_SURCHARGE of their base premium.
65	const highEnchantmentSurcharge = (item: Item): number =>
66	  surchargeWhen(
67	    item,
68	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
69	    HIGH_ENCHANTMENT_SURCHARGE,
70	  );
71	
72	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
73	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
74	// that is only spuriously above a whole number.
75	const roundUpInMHPCOsFavor = (amount: number): number =>
76	  Math.ceil(Number(amount.toFixed(6)));
77	
78	const basePremiumForItem = (item: Item): number =>
79	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
80	
81	// Each main item is priced on its own.
82	const mainItemsBasePremium = (items: Item[]): number =>
83	  sumOf(items, basePremiumForItem);
84	
85	const countByType = (items: Item[]): Map<string, number> => {
86	  const counts = new Map<string, number>();
87	  for (const item of items) {
88	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
89	  }
90	  return counts;
91	};
92	
93	// Components are grouped by type, and each group is block-priced.
94	const componentsBasePremium = (components: Item[]): number =>
95	  sumOf(countByType(components).values(), componentGroupBasePremium);
96	
97	const policyBasePremium = (items: Item[]): number =>
98	  mainItemsBasePremium(items.filter(isMainItem)) +
99	  componentsBasePremium(items.filter(isComponent));
100	
101	// Tier 1 — item-specific surcharges: computed off each affected item's base
102	// premium and summed across the policy. (e.g. curse; later high-enchantment.)
103	const itemSurcharges = (items: Item[]): number =>
104	  sumOf(items, (item) => curseSurcharge(item) + highEnchantmentSurcharge(item));
105	
106	// A policy-wide modifier adds `rate` of the policy base premium when its
107	// condition holds, and nothing otherwise.
108	const fractionOfPolicyBaseWhen = (
109	  policyBase: number,
110	  applies: boolean,
111	  rate: number,
112	): number => (applies ? rate * policyBase : 0);
113	
114	// Every new policy carries a surcharge equal to FIRST_INSURANCE_SURCHARGE of
115	// the policy base premium. It always applies, so it is computed directly
116	// rather than going through the conditional fractionOfPolicyBaseWhen helper.
117	const firstInsuranceSurcharge = (policyBase: number): number =>
118	  FIRST_INSURANCE_SURCHARGE * policyBase;
119	
120	// Long-standing customers (at or above the loyalty threshold) receive a
121	// discount equal to LOYALTY_DISCOUNT of the policy base premium.
122	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
123	  fractionOfPolicyBaseWhen(
124	    policyBase,
125	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
126	    LOYALTY_DISCOUNT,
127	  );
128	
129	// Every contract after the customer's first (a non-zero quote index) receives a
130	// discount equal to FOLLOWUP_DISCOUNT of the policy base premium.
131	const followUpDiscount = (policyBase: number, quoteIndex: number): number =>
132	  fractionOfPolicyBaseWhen(policyBase, quoteIndex >= 1, FOLLOWUP_DISCOUNT);
133	
134	// Tier 2 — policy-wide modifiers: each computed as a fraction of the policy
135	// base premium. Surcharges add; discounts subtract. (first-insurance surcharge,
136	// loyalty discount, follow-up discount.)
137	const policyWideModifiers = (
138	  policyBase: number,
139	  customer: Customer,
140	  quoteIndex: number,
141	): number =>
142	  firstInsuranceSurcharge(policyBase) -
143	  loyaltyDiscount(policyBase, customer) -
144	  followUpDiscount(policyBase, quoteIndex);
145	
146	export const quote = (
147	  customer: Customer,
148	  step: QuoteStep,
149	  quoteIndex: number,
150	): number => {
151	  const policyBase = policyBasePremium(step.items);
152	
153	  const total =
154	    policyBase +
155	    itemSurcharges(step.items) +
156	    policyWideModifiers(policyBase, customer, quoteIndex) +
157	    PROCESSING_FEE;
158	  return roundUpInMHPCOsFavor(total);
159	};
160	
161	interface Damage {
162	  itemType: string;
163	  amount: number;
164	}
165	
166	interface Incident {
167	  cause: string;
168	  damages: Damage[];
169	}
170	
171	interface ClaimResult {
172	  payout: number;
173	  remainingCap: number;
174	}
175	
176	const DEDUCTIBLE = 100;
177	const ENCHANTMENT_HALF_THRESHOLD = 8;
178	const HALF_REIMBURSEMENT = 0.5;
179	
180	// Items at or above the half-reimbursement enchantment threshold are reimbursed
181	// at only half the damage amount.
182	const isHalfReimbursed = (item: Item | undefined): boolean =>
183	  (item?.enchantment ?? 0) >= ENCHANTMENT_HALF_THRESHOLD;
184	
185	// What MHPCO reimburses for a single damage, before the deductible: half-
186	// reimbursed items (enchantment at or above the threshold) get half the damage
187	// amount; everything else gets the full amount. The full-amount branch covers
188	// both ordinary items and dragon-material items: dragon material is fully
189	// reimbursed, but half-reimbursement still wins when it also applies (a
190	// high-enchantment dragon item is reimbursed at half, not in full).
191	const reimbursedAmount = (item: Item | undefined, amount: number): number =>
192	  isHalfReimbursed(item) ? HALF_REIMBURSEMENT * amount : amount;
193	
194	// The net payout for a single damage: what MHPCO reimburses for the damaged
195	// item, less the per-damage deductible.
196	const netPayoutForDamage = (policyItems: Item[], damage: Damage): number => {
197	  const item = policyItems.find((i) => i.type === damage.itemType);
198	  return reimbursedAmount(item, damage.amount) - DEDUCTIBLE;
199	};
200	
201	export const claim = (policyItems: Item[], incident: Incident): ClaimResult => {
202	  const payout = sumOf(incident.damages, (damage) =>
203	    netPayoutForDamage(policyItems, damage),
204	  );
205	  return { payout, remainingCap: 0 };
206	};
